#!/usr/bin/env bash
# b-end-to-end.sh — 一次完整研学旅行项目全流程（B 端校采 end-to-end） SOP walkthrough for 研学营地教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="研学营地教育"
WORKFLOW="一次完整研学旅行项目全流程（B 端校采 end-to-end）"

usage() {
  cat <<EOF
b-end-to-end.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./b-end-to-end.sh             # interactive
  ./b-end-to-end.sh --dry-run
  ./b-end-to-end.sh --json
  ./b-end-to-end.sh --explain
  ./b-end-to-end.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "一次完整研学旅行项目全流程（B 端校采 end-to-end）" 工作流。

一句话: 从「学校/教育局有研学课时与采购需求」这一状态，走到「一次合规、有教育性、安全无事故、可评价的研学项目交付完毕并复盘」的状态——本行业 B 端的总 pipeline，其余 workflow（W3 课程/W4 安全/W5 基地/W7 采购）都是它的子流程。

入门 SOP 共 9 步, 失败模式自检 3 项。

相关心智模型:
  • 「研学是课程不是行程」——教育属性优先: 研学/营地的本体是**课程**（有学习目标—实施—评价闭环），不是**行程**（景点+讲解词）；从业者用「教育本质」作为对抗旅游化、获客化、速成化的立场锚与对客叙事。
  • 体验—反思闭环（Kolb 圈）——「经验无反思即旅游」: 学习不是「去过/动手过」就发生，而要走完「具体经验→反思观察→抽象概念化→主动实践」的圈；**「反思/复盘」环节的有无，是研学区别于旅游的命门工序**。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**需求对接**：与学校/教育局确认学段、人数、课时、预算、主题倾向、出行半径。who: 客户经理+教研。跳过后果：方案与校方课时/经费口径错位，立项即被否，前功尽弃。 evidence: [W-S006]"
  "**主题立项**：依教学目标定主题（红色/自然/科技/人文…），产出立项书。跳过后果：沦为「报旅行社线路」，无教育主线，触碰「只游不学」红线被监管/家长质疑。 evidence: [W-S012, W-S011]"
  "**课程设计**（详见 W3）：定学习目标+学科融合，按 LB/T 092 七步产出**研学手册**。跳过后果：行中无任务无反思，评价无依据，验收不过。 evidence: [W-S002]"
  "**踩点+选基地**（详见 W5）：实地踩线、按 T/CATS 002 核基地安全与容量、签约地接。跳过后果：图册选基地→现场食宿/安全/容量不符，行中崩盘。 evidence: [W-S008]"
  "**安全评估+应急预案+三层保险**（详见 W4）：风险评估、一车/一队一案、校方责任险+旅行社责任险+人身意外险三层投保。跳过后果：**无预案不准成行**；出事即重大法律与舆情风险。 evidence: [W-S013, W-S006]"
  "**报批备案**：向教育部门/学校提交活动方案+安全预案+应急预案+家长告知同意书，审核通过后方可成行。跳过后果：违规组织、出事追责加重、被通报除名。 evidence: [W-S006]"
  "**招生缴费 → 行前说明会**：缴费、面向学生/家长/带队师做安全与行程交底。跳过后果：家长信息不对称、临行投诉、突发时联络断链。 evidence: [W-S006]"
  "**行中双师带队**：研学导师管学习目标、学科教师/导游管行程、安全员管安全，按手册推进+每日小结。跳过后果：导游化讲解，学习目标落空。 evidence: [W-S003]"
  "**研学评价 → 复盘**：收手册/成果做评价（部分对接学分/综合素质评价），出复盘报告。跳过后果：成果无沉淀、无法对学校证明教育性、续约困难。 evidence: [W-S002, W-S005]"
)
declare -a FAILURE_MODES=(
  "**报批前置做反**：先招生收费再补报批，结果方案被驳回要退费、信誉受损。→ 把「报批通过」设为招生的硬前置闸门（先批后招）。 evidence: [W-S006]"
  "**教育性缺失被打回**：方案=旅行社线路换皮，无学习目标/无反思/无评价，被教育局核查认定「伪研学」。→ 立项即附「课标/综合实践活动方式对照表」自证教育性。 evidence: [W-S011]"
  "**双师退化为单导游**：现场只有导游讲解、无研学导师组织任务，学生「游而不学」，家长差评。→ 合同与排班锁定「研学导师+学科教师/导游+安全员」分列配置，不可一人兼。 evidence: [W-S003]"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "b-end-to-end-walkthrough"
fi
